var e=[{id:`L4_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`침식체도 침식체지만…… 엄청 불길한 기운이네.`,JPN:`侵食体も侵食体だけど……とても不吉な気配がするね。`,ENG:`I know we’re in a Corrupted Area... but this place feels unusually ominous.`,TWN:`雖然是有侵蝕體沒錯……但感覺好不安。`},stage:{bg:`REEDS_FIELD_02`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L5_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`이미 이곳은 나나하라의 옛 영지. 결계의 안쪽입니다.`,JPN:`すでにこちらは七原の旧領地。結界の奥です。`,ENG:`This is old Nanahara territory. We’re inside the enchanted barrier.`,TWN:`這裡已經是七原的舊領地，是在結界內。`},stage:{bg:`REEDS_FIELD_02`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L6_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`오로치의 봉인과 가까워지고 있으니 독기 또한 짙어지는 것이지요.`,JPN:`オロチの封印に近づいているため、毒が濃くなっているのでしょう。`,ENG:`The foulness in the air will thicken as we get closer to the seal of Orochi.`,TWN:`因爲離大蛇的封印越來越近，所以毒氣也越來越濃。`},stage:{bg:`REEDS_FIELD_02`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L7_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`정신이 흐트러지면 환각을 보게 될 테니 조심하십시오.`,JPN:`気をしっかり持たないと幻覚を見ますので注意してください。`,ENG:`Stay focused, otherwise you’ll see hallucinations.`,TWN:`請繃緊神經，否則會產生幻覺，千萬要小心。`},stage:{bg:`REEDS_FIELD_02`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_IDLE`},C:null,R:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L8_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`환각이라고?`,JPN:`幻覚って？`,ENG:`Hallucinations?`,TWN:`幻覺？`},stage:{bg:`REEDS_FIELD_02`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L10_1`,type:`dialog`,speaker:`CHIFUYU_NANA_NULL_NULL`,text:{KOREA:`시간이 없습니다. 이쪽으로.`,JPN:`時間がありません。こちらへ。`,ENG:`We don’t have the time. Come this way.`,TWN:`沒時間跟你解釋，往這邊。`},stage:{bg:`REEDS_FIELD_02`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`CHIFUYU_NANA_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`MINATO_NANA_NULL_NULL`,text:{KOREA:`자, 잠깐만!`,JPN:`ま、待って！`,ENG:`W-wait!`,TWN:`等…等一下！`},stage:{bg:`REEDS_FIELD_02`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`MINATO_NANA_NULL_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L14_1`,type:`dialog`,speaker:`KANADE_JAPAN_NULL_MASKED`,text:{KOREA:`…….`,JPN:`……`,ENG:`...`,TWN:`……`},stage:{bg:`REEDS_FIELD_02`,bgm:`CUTSCENE_AMBIENT_WIND`,filter:`NCFT_NORMAL`,slots:{L:null,C:{char_id:`KANADE_JAPAN_NULL_MASKED`,face:`UNIT_SERIOUS2`},R:null}},sfx:`FX_CUTSCEN_BELL`}];export{e as default};